from threading import Semaphore


# Hierarchy of execution:
#   test fizzbuzz (%15) first, then buzz (%5), then fizz (%3), else the number.
# `number` is the single dispatcher: it walks 1..n and, per value, releases
# exactly ONE worker's semaphore then blocks on `done_turn` until it finishes.
# No Barrier needed because only one worker executes per number.
class FizzBuzz:
    def __init__(self, n: int):
        self.n = n
        self.fizzbuzz_turn = Semaphore(0)
        self.buzz_turn = Semaphore(0)
        self.fizz_turn = Semaphore(0)
        self.done_turn = Semaphore(0)

    # printFizz() outputs "fizz"
    def fizz(self, printFizz: 'Callable[[], None]') -> None:
        for i in range(3, self.n + 1, 3):
            if i % 5 != 0:
                self.fizz_turn.acquire()
                printFizz()
                self.done_turn.release()

    # printBuzz() outputs "buzz"
    def buzz(self, printBuzz: 'Callable[[], None]') -> None:
        for i in range(5, self.n + 1, 5):
            if i % 3 != 0:
                self.buzz_turn.acquire()
                printBuzz()
                self.done_turn.release()

    # printFizzBuzz() outputs "fizzbuzz"
    def fizzbuzz(self, printFizzBuzz: 'Callable[[], None]') -> None:
        for i in range(15, self.n + 1, 15):
            self.fizzbuzz_turn.acquire()
            printFizzBuzz()
            self.done_turn.release()

    # printNumber(x) outputs "x", where x is an integer.
    def number(self, printNumber: 'Callable[[int], None]') -> None:
        for i in range(1, self.n + 1):
            if i % 15 == 0:
                self.fizzbuzz_turn.release()
                self.done_turn.acquire()
            elif i % 5 == 0:
                self.buzz_turn.release()
                self.done_turn.acquire()
            elif i % 3 == 0:
                self.fizz_turn.release()
                self.done_turn.acquire()
            else:
                printNumber(i)

from threading import Semaphore

# we need to print zeros before calling odd/even
# we assume the program starts from zero, then odd, then even as sequence
# each thread runs its own range, so the counts fall out naturally:
#   zero prints n times; odd prints ceil(n/2) times; even prints floor(n/2)
class ZeroEvenOdd:
    def __init__(self, n):
        self.n = n

        self.zero_turn = Semaphore(1)
        self.odd_turn = Semaphore(0)
        self.even_turn = Semaphore(0)

    # printNumber(x) outputs "x", where x is an integer.
    def zero(self, printNumber: 'Callable[[int], None]') -> None:
        for i in range(1, self.n + 1):
            self.zero_turn.acquire()
            printNumber(0)
            if i % 2 == 1:
                self.odd_turn.release()
            else:
                self.even_turn.release()

    def even(self, printNumber: 'Callable[[int], None]') -> None:
        for i in range(2, self.n + 1, 2):
            self.even_turn.acquire()
            printNumber(i)
            self.zero_turn.release()

    def odd(self, printNumber: 'Callable[[int], None]') -> None:
        for i in range(1, self.n + 1, 2):
            self.odd_turn.acquire()
            printNumber(i)
            self.zero_turn.release()

from typing import List
from concurrent.futures import ThreadPoolExecutor

class Solution:
    def crawl(self, startUrl: str, htmlParser: 'HtmlParser') -> List[str]:
        hostname = self.getHost(startUrl)
        visited = {startUrl}

        with ThreadPoolExecutor(max_workers=10) as executor:
            q = [startUrl]

            while q:
                next_level = []

                for urls in executor.map(htmlParser.getUrls, q):
                    for url in urls:
                        if self.getHost(url) == hostname and url not in visited:
                            visited.add(url)
                            next_level.append(url)

                q = next_level

        return list(visited)

    def getHost(self, url: str) -> str:
        return url.replace("http://", "").split("/")[0]

from collections import Counter
# First create a counter of words across each word
# Traverse the list with this approach and put each one into the map
# indexed by counter item's frozenset
class Solution:
    def groupAnagrams(self, strs: List[str]) -> List[List[str]]:
        anagram_hashmap = {}
        for word in strs:
            char_counter_frozenset = frozenset(Counter(word).items())
            if char_counter_frozenset in anagram_hashmap:
                anagram_hashmap[char_counter_frozenset].append(word)
            else: 
                anagram_hashmap[char_counter_frozenset] = [word]
        # need to output list from map
        output = []
        for word_list in anagram_hashmap.values():
            output.append(word_list)
        return output

class Solution:
    def climbStairs(self, n: int) -> int:
        cache = [-1] *n
        def dfs(i):
            if i >= n:
                return i == n
            if cache[i] != -1:
                return cache[i]
            cache[i] = dfs(i+1) + dfs(i+2)
            return cache[i]

        return dfs(0)

