class Solution:
    def hasDuplicate(self, nums: List[int]) -> bool:
        occurance_counter = Counter(nums)
        for k, v in occurance_counter.items():
            if v > 1:
                return True
        return False

from collections import Counter
class Solution:
    def isAnagram(self, s: str, t: str) -> bool:
        s_counter = Counter(s)
        t_counter = Counter(t)
        return s_counter == t_counter

class Solution:
    def isPalindrome(self, s: str) -> bool:
        left = 0
        right = len(s) - 1

        while left < right:
            while left < right and not s[left].isalnum():
                left += 1
            while left < right and not s[right].isalnum():
                right -= 1
            if s[left].lower() != s[right].lower():
                return False
            left += 1
            right -= 1
        return True

class Solution:
    def encode(self, strs: List[str]) -> str:
        output = []
        for s in strs:
            output.append(str(len(s)))
            output.append("#")
            output.append(s)
        return "".join(output)

    def decode(self, s: str) -> List[str]:
        output = []
        i = 0
        while i < len(s):
            j = i
            while s[j] != "#":
                j += 1
            length = int(s[i:j])
            i = j + 1
            j = j + 1 + length
            word = s[i:j]
            output.append(word)
            i = j
        return output

class Solution:
    def threeSum(self, nums: List[int]) -> List[List[int]]:
        output = set()
        nums.sort()
        for i, a in enumerate(nums):
            if a > 0:
                break
            if i > 0 and nums[i] == nums[i-1]:
                continue
            l, r = i + 1, len(nums) - 1
            while l < r:
                threeSum = nums[i] + nums[l] + nums[r]
                if threeSum > 0:
                    r -= 1
                elif threeSum < 0:
                    l += 1
                else:
                    output.add((a, nums[l], nums[r]))
                    l += 1
                    r -= 1
        return [list(x) for x in output]

from collections import Counter
class Solution:
    def topKFrequent(self, nums: List[int], k: int) -> List[int]:
        counter = Counter(nums)
        counter = sorted(counter, key=counter.get, reverse=True)
        return counter[:k]

class Solution:
    def twoSum(self, nums: List[int], target: int) -> List[int]:
        hash_map = {}
        output_list = []
        for index, num in enumerate(nums):
            difference_to_target = target - num
            if difference_to_target in hash_map:
                return [hash_map[difference_to_target], index]
            hash_map[num] = index
        return output_list

from typing import List


def get_word_length(word: str) -> int:
    return len(word)

def get_abs_val(num: int) -> int:
    return abs(num)

def sort_words(words: List[str]) -> List[str]:
    return sorted(words, key=get_word_length, reverse=True)


def sort_numbers(numbers: List[int]) -> List[int]:
    return sorted(numbers, key = get_abs_val)


